SELECT COUNT(DISTINCT program_id) 
FROM program_optimizers 
WHERE optimizer_id = 1;

SELECT optimizer_id
FROM program_optimizers
WHERE program_id = 1;

SELECT COUNT(DISTINCT p.program_id) AS num_programs_with_variant
FROM programs p
JOIN program_variants pv ON p.program_id = pv.program_id;

SELECT name
FROM programs
WHERE upload_date = (SELECT MIN(upload_date) FROM programs);

SELECT MAX(version_count) AS max_versions
FROM (
  SELECT program_id, COUNT(*) AS version_count
  FROM versions
  GROUP BY program_id
) AS version_counts;
